def kth_largest_element(nums, k):
    """
    Optimal: min-heap of size k.
    En büyük k. eleman için tek geçişli O(n log k).
    """
    import heapq
    heap = []
    for num in nums:
        if len(heap) < k:
            heapq.heappush(heap, num)
        elif num > heap[0]:
            heapq.heapreplace(heap, num)
    return heap[0]

